#include "mock_egtm_atom_3_phase_inverter_pwm.h"
#include "IfxPort.h"
#include "IfxEgtm.h"
#include "IfxEgtm_Cmu.h"
#include "IfxEgtm_Pwm.h"

/* MODULE instances */
Ifx_EGTM MODULE_EGTM = {0u};
Ifx_P MODULE_P00 = {0u};
Ifx_P MODULE_P02 = {0u};
Ifx_P MODULE_P10 = {0u};
